class Solution:
    def smallestDivisor(self, nums, threshold):
        """
        :type nums: List[int]
        :type threshold: int
        :rtype: int
        """
        def sum_with_divisor(divisor):
            return sum((num + divisor - 1) // divisor for num in nums)

        left, right = 1, max(nums)

        while left < right:
            mid = (left + right) // 2
            if sum_with_divisor(mid) <= threshold:
                right = mid
            else:
                left = mid + 1

        return left
